#include <stdio.h>
#include <stdlib.h>

typedef struct {
    int *data;
    int size;
    int capacity;
} DynamicArray;

void init(DynamicArray *arr, int capacity) {
    arr->data = (int *)malloc(capacity * sizeof(int));
    arr->size = 0;
    arr->capacity = capacity;
}

void resize(DynamicArray *arr, int newCapacity) {
    arr->data = (int *)realloc(arr->data, newCapacity * sizeof(int));
    arr->capacity = newCapacity;
}

void append(DynamicArray *arr, int value) {
    if(arr->size == arr->capacity) {
        resize(arr, arr->capacity * 2);
    }
    arr->data[arr->size++] = value;
}

int get(DynamicArray *arr, int index) {
    if(index < 0 || index >= arr->size) {
        return -1;  // Error
    }
    return arr->data[index];
}

void set(DynamicArray *arr, int index, int value) {
    if(index >= 0 && index < arr->size) {
        arr->data[index] = value;
    }
}

int pop(DynamicArray *arr) {
    if(arr->size == 0) return -1;
    return arr->data[--arr->size];
}

void destroy(DynamicArray *arr) {
    free(arr->data);
    arr->data = NULL;
    arr->size = arr->capacity = 0;
}

